package com.example.nofiltercoffee; import android.view.*; import android.widget.*; import androidx.recyclerview.widget.*; import java.util.*;
public class CartAdapter extends RecyclerView.Adapter<CartAdapter.VH>{public interface Listener{void onCartChanged();} ArrayList<CartItem> list; Listener l; public CartAdapter(ArrayList<CartItem> list,Listener l){this.list=list;this.l=l;} public VH onCreateViewHolder(ViewGroup p,int v){return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_cart,p,false));} public void onBindViewHolder(VH h,int p){CartItem i=list.get(p); h.n.setText(i.product.name);h.o.setText(i.options);h.price.setText("Rs. "+i.getTotal());h.qty.setText(String.valueOf(i.quantity)); h.plus.setOnClickListener(v->{CartManager.increase(i);notifyDataSetChanged();if(l!=null)l.onCartChanged();}); h.minus.setOnClickListener(v->{CartManager.decrease(i);notifyDataSetChanged();if(l!=null)l.onCartChanged();});} public int getItemCount(){return list.size();} static class VH extends RecyclerView.ViewHolder{TextView n,o,price,qty,plus,minus;VH(View v){super(v);n=v.findViewById(R.id.txtName);o=v.findViewById(R.id.txtOptions);price=v.findViewById(R.id.txtPrice);qty=v.findViewById(R.id.txtQty);plus=v.findViewById(R.id.btnPlus);minus=v.findViewById(R.id.btnMinus);}}}
